class Solution:
    def dp(self, coins, amount):
        if amount == 0:
            return 0
        memo = {}
        def _dp(amount):
            if amount in memo:
                return memo[amount]
            if amount == 0:
                memo[amount] = 0
                return 0
            min_coins = float('inf')
            for coin in coins:
                if amount >= coin:
                    min_coins = min(min_coins, _dp(amount - coin) + 1)
            memo[amount] = min_coins
            return min_coins
        return _dp(amount)

    def __init__(self):
        pass

    def solve(self, coins, amount):
        return self.dp(coins, amount)

    def output(self, coins, amount):
        result = self.solve(coins, amount)
        if result == float('inf'):
            return -1
        return result

    def processInput(self, input_data):
        coins, amount = list(map(int, input_data.split()))
        return coins, amount

    def main(self):
        input_data = input()
        coins, amount = self.processInput(input_data)
        output = self.output(coins, amount)
        print(output)

