#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>
#include <climits>

using namespace std;

class Solution {
public:
    int dp(vector<int>& coins, int amount) {
        if (amount == 0) return 0;
        int min_coins = INT_MAX;
        vector<int> memo(amount + 1, INT_MAX);
        memo[0] = 0;
        for (int i = 1; i <= amount; ++i)
        {
            for (int coin : coins)
            {
                if (i >= coin)
                    memo[i] = min(memo[i], memo[i - coin] + 1);
            }
        }
        return memo[amount] == INT_MAX ? -1 : memo[amount];
    }
public:
};

int main() {
    Solution obj;
    int coins_size, amount;
    cin >> coins_size >> amount;
    vector<int> coins(coins_size);
    for (int i = 0; i < coins_size; ++i) cin >> coins[i];
    cout << obj.dp(coins, amount) << endl;
    return 0;
}
